#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
static char buf[100000], * pa(buf), * pb(buf);
#define gc pa == pb && (pb = (pa = buf) + fread(buf, 1, 100000, stdin), pa == pb) ? EOF : *pa++
inline int read()
{
	int num = 0, f = 1;
	char c = gc;
	while (c < '0' || c > '9')
	{
		if (c == '-')f = -1;
		c = gc;
	}
	while (c >= '0' && c <= '9')
	{
		num = num * 10 + (c - '0');
		c = gc;
	}
	return num * f;
}
inline void write(long long x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
}
CI MAXN = 1e5 + 5;
int n, mx = -inf, m;
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	n = read(), m = read();
	for (int i = 1; i <= n; ++i)
	{
		mx = max(mx, read());
	}
	for (int i = 1; i <= m; ++i)
	{
		mx += max(read(), 0 - (n == 1) * inf);
	}
	write(mx);
	return false;
}
